/* ─── Utilities ─── */
function R({ children, delay = 0, style = {} }) {
  const [v, setV] = useState(false);
  const ref = useRef(null);
  useEffect(() => {
    const obs = new IntersectionObserver(([e]) => { if (e.isIntersecting) setV(true); }, { threshold: 0.04 });
    if (ref.current) obs.observe(ref.current);
    return () => obs.disconnect();
  }, []);
  return (
    <div ref={ref} style={{ ...style, opacity: v ? 1 : 0, transform: v ? "none" : "translateY(16px)",
      transition: `opacity 0.6s cubic-bezier(.25,.46,.45,.94) ${delay}s, transform 0.6s cubic-bezier(.25,.46,.45,.94) ${delay}s`,
    }}>{children}</div>
  );
}

/* Logo marquee — embedded base64 logos */
function LogoMarquee({ logos, speed = 50 }) {
  return (
    <div style={{ overflow: "hidden", whiteSpace: "nowrap" }}>
      <div style={{ display: "inline-flex", alignItems: "center", animation: `mq ${speed}s linear infinite` }}>
        {[...logos, ...logos, ...logos].map((src, i) => (
          <img key={i} src={src} alt="" style={{ height: 52, width: "auto", margin: "0 40px", flexShrink: 0, objectFit: "contain", filter: "grayscale(100%)", opacity: 0.45, transition: "all 0.3s" }}
            onMouseEnter={e => { e.target.style.filter = "grayscale(0%)"; e.target.style.opacity = "1"; }}
            onMouseLeave={e => { e.target.style.filter = "grayscale(100%)"; e.target.style.opacity = "0.45"; }} />
        ))}
      </div>
      <style>{`@keyframes mq { 0%{transform:translateX(0)} 100%{transform:translateX(-33.333%)} }`}</style>
    </div>
  );
}

