/* Pentagram-style vertical auto-scroll — compact, mouse controls direction */
function VerticalScroll() {
  const containerRef = useRef(null);
  const scrollPos = useRef(0);
  const speed = useRef(0.15);
  const raf = useRef(null);
  const items = [
    "Kitap Tasarımı", "Baskı Danışmanlığı", "ePub Yayıncılık", "ISBN Yönetimi",
    "Dağıtım", "Kapak Tasarımı", "Redaksiyon", "DVD Üretim",
    "Blu-ray Üretim", "Koleksiyonluk Baskı", "Çeviri Editörlüğü", "Mizanpaj",
    "Kitap Tasarımı", "Baskı Danışmanlığı", "ePub Yayıncılık", "ISBN Yönetimi",
    "Dağıtım", "Kapak Tasarımı", "Redaksiyon", "DVD Üretim",
    "Blu-ray Üretim", "Koleksiyonluk Baskı", "Çeviri Editörlüğü", "Mizanpaj",
  ];

  useEffect(() => {
    const el = containerRef.current;
    if (!el) return;
    const parent = el.parentElement;
    const handleMouse = (e) => {
      const rect = parent.getBoundingClientRect();
      const y = (e.clientY - rect.top) / rect.height;
      speed.current = (y - 0.5) * 1.0;
    };
    const handleLeave = () => { speed.current = 0.15; };
    const tick = () => {
      scrollPos.current += speed.current;
      const totalH = el.scrollHeight / 2;
      if (scrollPos.current > totalH) scrollPos.current -= totalH;
      if (scrollPos.current < 0) scrollPos.current += totalH;
      el.style.transform = `translateY(${-scrollPos.current}px)`;
      raf.current = requestAnimationFrame(tick);
    };
    parent.addEventListener("mousemove", handleMouse);
    parent.addEventListener("mouseleave", handleLeave);
    raf.current = requestAnimationFrame(tick);
    return () => {
      parent.removeEventListener("mousemove", handleMouse);
      parent.removeEventListener("mouseleave", handleLeave);
      cancelAnimationFrame(raf.current);
    };
  }, []);

  return (
    <div style={{ width: 280, height: 190, overflow: "hidden", position: "relative", borderLeft: `1px solid ${C.border}` }}>
      {/* Fade edges */}
      <div style={{ position: "absolute", top: 0, left: 0, right: 0, height: 32, background: `linear-gradient(to bottom, ${C.white}, transparent)`, zIndex: 2, pointerEvents: "none" }} />
      <div style={{ position: "absolute", bottom: 0, left: 0, right: 0, height: 32, background: `linear-gradient(to top, ${C.white}, transparent)`, zIndex: 2, pointerEvents: "none" }} />
      <div ref={containerRef} style={{ willChange: "transform" }}>
        {items.map((item, i) => (
          <div key={i} style={{
            padding: "8px 24px",
            fontSize: 15, fontWeight: 500, color: C.muted, fontFamily: font, whiteSpace: "nowrap",
          }}>
            {item}
          </div>
        ))}
      </div>
    </div>
  );
}

/* Drag-to-scroll horizontal slider */
function DragSlider({ children }) {
  const ref = useRef(null);
  const isDragging = useRef(false);
  const startX = useRef(0);
  const scrollLeft = useRef(0);

  const onDown = (e) => {
    isDragging.current = true;
    startX.current = e.pageX - ref.current.offsetLeft;
    scrollLeft.current = ref.current.scrollLeft;
    ref.current.style.cursor = "grabbing";
    ref.current.style.scrollSnapType = "none";
  };
  const onUp = () => {
    isDragging.current = false;
    if (ref.current) {
      ref.current.style.cursor = "grab";
      ref.current.style.scrollSnapType = "x mandatory";
    }
  };
  const onMove = (e) => {
    if (!isDragging.current) return;
    e.preventDefault();
    const x = e.pageX - ref.current.offsetLeft;
    ref.current.scrollLeft = scrollLeft.current - (x - startX.current);
  };

  useEffect(() => {
    document.addEventListener("mouseup", onUp);
    return () => document.removeEventListener("mouseup", onUp);
  }, []);

  return (
    <div ref={ref}
      onMouseDown={onDown}
      onMouseMove={onMove}
      onMouseLeave={onUp}
      style={{
        display: "flex", gap: 16, maxWidth: 1400, margin: "0 auto", padding: "0 40px",
        overflowX: "auto", scrollSnapType: "x mandatory", scrollBehavior: "smooth",
        cursor: "grab", userSelect: "none",
        msOverflowStyle: "none", scrollbarWidth: "none",
      }}>
      {children}
      <div style={{ flex: "0 0 40px" }} />
    </div>
  );
}

